# -*- coding: utf-8 -*-

import AS
import networkx as nx
import pylab

def logToCount(logList, countList, int MAX_COUNT, int STEP=1000):
  timestamps = []
  cdef int time = 0
  cdef int i = 0
  cdef int t = 0
  cdef int index = 0
  for line in logList:
    time = line[2]
    timestamps.append(time)

  for i in range(MAX_COUNT):
    countList.append(0)
  for t in timestamps:
    index = int(t/STEP)
    if index >= MAX_COUNT:
      return
    countList[index] += 1

cdef class Network:
  cdef public dict addr_to_as, as_dict
  cdef public list top_as_numbers

  def __init__(self):
    self.addr_to_as = {}
    self.as_dict = {}
    self.top_as_numbers = []

  def loadRelationFile(self, filename, calculatePath=False):
    G = nx.Graph()
    for line in open(filename, 'r'):
      if line.startswith('#'):
        continue  # コメント行
      para = line.split('|')
      if len(para) != 3:
        continue  # 改行 or その他の関係の無い行

      node1 = int(para[0])
      node2 = int(para[1])
      connection_type = int(para[2])
      if node1 not in self.as_dict:
        self.as_dict[node1] = AS.AS(node1)
        G.add_node(node1)
      if node2 not in self.as_dict:
        self.as_dict[node2] = AS.AS(node2)
        G.add_node(node1)

      if (connection_type == -1):
        # transit connection, node1 provide node2
        provider = self.as_dict[node1]
        customer = self.as_dict[node2]
        provider.customerNodes[customer.as_number] = customer
        customer.providerNodes[provider.as_number] = provider
        # customer -> provider
      elif (connection_type == 0):
        # peer connection
        peer1 = self.as_dict[node1]
        peer2 = self.as_dict[node2]
        peer1.peerNodes[peer2.as_number] = peer2
        peer2.peerNodes[peer1.as_number] = peer1
      G.add_edge(node1, node2)

    if calculatePath==True:
      paths = nx.shortest_path(G)
      node1 = None
      node2 = None
      src = 0
      dst = 0
      path = None
      for src in sorted(paths.keys()):
        for dst in sorted(paths[src].keys()):
          path = paths[src][dst]
          if (src==dst or len(path)<2):
            continue
          else:
            srcNode = self.as_dict[src]
            srcNode.customerTable[dst] = (path[1], len(path))

    return len(self.as_dict)

  def searchTopAS(self):
    for node in self.as_dict.values():
      if len(node.providerNodes) == 0:
        self.top_as_numbers.append(node.as_number)

    return len(self.top_as_numbers)

  def exchangeRoutingTable(self):
    # トップレベルASから再帰的に下位ASのcustomerTableを統合
    for as_number in self.top_as_numbers:
      top_as = self.as_dict[as_number]
      top_as.mergeCustomerTable()

    # 全ASでピアにcustomerTableの内容を通知
    for node in self.as_dict.values():
      node.mergePeerTable()

    # トップレベルASから再帰的に下位ASにcustomerTable, peerTable,
    # providerTableの内容を通知
    for as_number in self.top_as_numbers:
      top_as = self.as_dict[as_number]
      top_as.transit()

  def distributeNetAddr(self):
    seq = 1
    for node in self.as_dict.values():
      networkAddr = seq << 16   # 上位16ビットがネットワーク部、下位16ビットがホスト部
      node.networkAddress = networkAddr
      node.netmask = 0xFFff0000
      seq += 1
      self.addr_to_as[networkAddr] = node.as_number

  def traceroute(self, strSrc, strDst, int startTime=0, int packets=3):
    cdef int delay = 13   # delay per router
    cdef int elapsed = 0 # ms
    cdef int src = AS.AS.strAddrToInt(strSrc)
    cdef int dst = AS.AS.strAddrToInt(strDst)
    cdef int mask = 0xFFff0000
    cdef int srcNet = src & mask
    cdef int dstNet = dst & mask

    cdef int src_as_number = self.addr_to_as[srcNet]
    cdef int dst_as_number = self.addr_to_as[dstNet]

    current = self.as_dict[src_as_number]

    cdef int i, nexthop
    while True:
      # ホップ毎に指定されたパケット数を送信する
      for i in range(packets):
        elapsed += delay
        current.addLog(src, dst, startTime + elapsed)
      route = None
      if dst_as_number in current.customerTable:
        route = current.customerTable[dst_as_number]
      elif dst_as_number in current.peerTable:
        route = current.peerTable[dst_as_number]
      elif dst_as_number in current.providerTable:
        route = current.providerTable[dst_as_number]
      else:
        return -1

      nexthop = route[0]
      if nexthop == -1:
        break
      else:
        current = self.as_dict[nexthop]

    return elapsed

  def clearASLog(self):
    for node in self.as_dict.values():
      node.clearLog()

from ._exception import ValidrError, Invalid, mark_index, mark_key


def _update_wrapper(f):
    def wrapper(__, *args, desc=None, **kwargs):
        kwargs.setdefault('optional', False)
        _validator = f(__, *args, **kwargs)
        params = [repr(x) for x in args]
        params.extend(['{}={}'.format(k, repr(v)) for k, v in kwargs.items()])
        params = ', '.join(params)
        _validator.__module__ = f.__module__
        _validator.__name__ = '{}({})'.format(f.__name__, params)
        _validator.__qualname__ = '{}({})'.format(f.__qualname__, params)
        _validator.__doc__ = desc
        return _validator
    wrapper.__module__ = f.__module__
    wrapper.__name__ = f.__name__
    wrapper.__qualname__ = f.__qualname__
    wrapper.__doc__ = f.__doc__
    return wrapper


cdef _value_is_none_and_optional(value, bint optional):
    if value is None:
        if optional:
            return True
        else:
            raise Invalid('required')
    return False


@_update_wrapper
def list_validator(inner, int minlen=0, int maxlen=1024,
                   bint unique=False, bint optional=False):
    def _validator(value):
        if _value_is_none_and_optional(value, optional):
            return None
        try:
            value = enumerate(value)
        except TypeError:
            raise Invalid('not list')
        result = []
        cdef int i = -1
        for i, x in value:
            if i >= maxlen:
                raise Invalid('list length must <= %d' % maxlen)
            with mark_index(i):
                v = inner(x)
                if unique and v in result:
                    raise Invalid('not unique')
            result.append(v)
        if i + 1 < minlen:
            raise Invalid('list length must >= %d' % minlen)
        return result
    return _validator


@_update_wrapper
def merged_validator(list validators, bint optional=False):
    def _validator(value):
        if _value_is_none_and_optional(value, optional):
            return None
        result = {}
        for v in validators:
            result.update(v(value))
        return result
    return _validator


@_update_wrapper
def dict_validator(list inners, bint optional=False):
    def _validator(value):
        if _value_is_none_and_optional(value, optional):
            return None
        # use dict instead of Mapping can speed up about 30%
        # so use dict until someone meet problems and need Mapping
        if isinstance(value, dict):
            get_item = _get_dict_value
        else:
            get_item = _get_object_value
        result = {}
        cdef str k
        for k, inner in inners:
            with mark_key(k):
                result[k] = inner(get_item(value, k))
        return result
    return _validator


cdef _get_dict_value(obj, str key):
    return obj.get(key, None)


cdef _get_object_value(obj, str key):
    return getattr(obj, key, None)
